import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read the entire line including spaces

        // Define a maximum buffer size to prevent buffer overflow
        int maxBufferSize = 10;

        // Copy only up to the maximum allowed characters into a dynamically-sized buffer
        char[] buffer = new char[Math.min(name.length(), maxBufferSize)];

        // Copy the user input into the fixed-size buffer with proper bounds checking
        name.getChars(0, buffer.length, buffer, 0);

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

